@dataclass
class VADConfig:
    threshold: float = 0.02           # energy threshold for speech detection
    min_speech_duration: float = 0.5  # seconds
    silence_duration: float = 0.8     # seconds of silence to end utterance

class RealtimeVoiceAgent:
    def start(self):
        self.is_listening = True
        capture_thread = threading.Thread(target=self._capture_audio)
        process_thread = threading.Thread(target=self._process_audio)
        capture_thread.start()
        process_thread.start()
        return capture_thread, process_thread

def _process_audio(self):
    audio_buffer, speech_detected, silence_frames = [], False, 0
    while self.is_listening:
        try:
            audio_chunk = self.audio_queue.get(timeout=0.1)
        except queue.Empty:
            continue
        # Energy-based VAD — prototype only
        energy = np.sqrt(np.mean(audio_chunk ** 2))
        if energy > self.vad_config.threshold:
            speech_detected = True
            silence_frames = 0
            audio_buffer.append(audio_chunk)
        elif speech_detected:
            silence_frames += 1
            audio_buffer.append(audio_chunk)
            if silence_frames > self.vad_config.silence_duration * 10:
                if len(audio_buffer) > self.vad_config.min_speech_duration * 10:
                    audio_data = np.concatenate(audio_buffer)
                    self._handle_utterance(audio_data)
                audio_buffer, speech_detected, silence_frames = [], False, 0
